import{j as e,b as t,c as n,a2 as s}from"./chunks/framework.BDRKwY9B.js";const u=JSON.parse('{"title":"内核运行时","description":"Kernel 的调度机制——从旧 loop.py 线性轮询到事件总线驱动的过渡。","frontmatter":{"title":"内核运行时","description":"Kernel 的调度机制——从旧 loop.py 线性轮询到事件总线驱动的过渡。","order":6},"headers":[],"relativePath":"architecture/kernel-runtime.md","filePath":"architecture/kernel-runtime.md","lastUpdated":1778837174000}'),p={name:"architecture/kernel-runtime.md"};function d(o,a,i,l,r,c){return t(),n("div",null,[...a[0]||(a[0]=[s(`<h1 id="内核运行时" tabindex="-1">内核运行时 <a class="header-anchor" href="#内核运行时" aria-label="Permalink to &quot;内核运行时&quot;">​</a></h1><p>Kernel 是 AuroraBot 的调度心脏。<strong>当前代码处于过渡期</strong>：旧调度器 <code>loop.py</code> 仍在运行，新的事件总线 + Node 调度模型已在 <code>base.py</code> 中就位，等待 <code>node_factory.py</code> 完成填充后切换。</p><h2 id="当前运行态-loop-py-线性调度" tabindex="-1">当前运行态：loop.py 线性调度 <a class="header-anchor" href="#当前运行态-loop-py-线性调度" aria-label="Permalink to &quot;当前运行态：loop.py 线性调度&quot;">​</a></h2><p>旧调度器位于 <code>src/brain/kernel/loop.py</code>，采用轮询 + 优先级模型：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每个周期：</span></span>
<span class="line"><span>  1. 遍历所有 Agent，调用 propose() 收集提案</span></span>
<span class="line"><span>  2. 按优先级排序，选择得分最高的 Agent</span></span>
<span class="line"><span>  3. 调用该 Agent 的 step()，执行一步</span></span>
<span class="line"><span>  4. 如果该步是&quot;空闲&quot;结果，结束本轮</span></span>
<span class="line"><span>  5. 否则回到 2，最多执行 MAX_AGENT_STEPS_PER_TICK 步</span></span></code></pre></div><h3 id="当前注册的-agent" tabindex="-1">当前注册的 Agent <a class="header-anchor" href="#当前注册的-agent" aria-label="Permalink to &quot;当前注册的 Agent&quot;">​</a></h3><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">DEFAULT_AGENT_KEYS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;plan&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;expand&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;execute&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>这三个 Agent 对应旧流水线的三个阶段。注册表在 <code>agent_factory.py</code> 中：</p><table tabindex="0"><thead><tr><th>Key</th><th>类</th><th>职责</th></tr></thead><tbody><tr><td><code>plan</code></td><td><code>PlanAgent</code></td><td>从事件队列识别意图，生成计划</td></tr><tr><td><code>expand</code></td><td><code>ExpandAgent</code></td><td>将计划展开为原子动作</td></tr><tr><td><code>execute</code></td><td><code>ExecuteAgent</code></td><td>调用 App 命令执行</td></tr></tbody></table><h2 id="目标态-事件总线-node-调度" tabindex="-1">目标态：事件总线 + Node 调度 <a class="header-anchor" href="#目标态-事件总线-node-调度" aria-label="Permalink to &quot;目标态：事件总线 + Node 调度&quot;">​</a></h2><p>迁移完成后，Kernel 的调度将转向事件驱动模型：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>事件循环：</span></span>
<span class="line"><span>  1. 文件变更 → 事件总线广播 FileEvent</span></span>
<span class="line"><span>  2. 所有 Node 的 on_event() 被调用</span></span>
<span class="line"><span>  3. 匹配的 Node 进入 READY 状态</span></span>
<span class="line"><span>  4. 调度器按优先级从 READY 队列中选择 Node</span></span>
<span class="line"><span>  5. 调用 execute()，产出 FileUpdate</span></span>
<span class="line"><span>  6. 文件写入触发新一轮 FileEvent → 回到 1</span></span></code></pre></div><p>关键变化：</p><table tabindex="0"><thead><tr><th>维度</th><th>旧调度</th><th>新调度</th></tr></thead><tbody><tr><td>触发方式</td><td>定时轮询（interval）</td><td>事件驱动（文件变更）</td></tr><tr><td>调度对象</td><td>Agent（propose / step）</td><td>Node（on_event / execute）</td></tr><tr><td>激活判断</td><td>Agent 内部逻辑</td><td>声明式 <code>guards</code> + <code>FileEvent</code></td></tr><tr><td>产出</td><td>命令调用</td><td><code>FileUpdate</code> + 命令调用</td></tr><tr><td>流程控制</td><td>无（硬编码顺序）</td><td>Router 节点（Switch / Loop / Merge）</td></tr></tbody></table><h2 id="heartbeatrouter-—-自主意识脉冲" tabindex="-1">HeartbeatRouter — 自主意识脉冲 <a class="header-anchor" href="#heartbeatrouter-—-自主意识脉冲" aria-label="Permalink to &quot;HeartbeatRouter — 自主意识脉冲&quot;">​</a></h2><p>新架构的核心创新之一：系统不再等待外部输入。<code>HeartbeatRouter</code> 定时产生脉冲事件（<code>heartbeat.tick</code>），驱动 <code>GoalGeneratorAgent</code> 在沉默过久时主动生成意图。</p><p>这使 AuroraBot 从&quot;回应用户的镜子&quot;变成&quot;会自己呼吸的生命体&quot;——她不是因为有人说话才醒来，而是内部的钟摆从不停止。</p><h2 id="当前过渡状态" tabindex="-1">当前过渡状态 <a class="header-anchor" href="#当前过渡状态" aria-label="Permalink to &quot;当前过渡状态&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/brain/</span></span>
<span class="line"><span>  kernel/</span></span>
<span class="line"><span>    base.py           ← ✅ Node/Agent/Router 基类就位</span></span>
<span class="line"><span>    agent_base.py     ← 🔄 旧 Agent 体系（运行中）</span></span>
<span class="line"><span>    agent_factory.py  ← 🔄 旧 Agent 注册表（运行中）</span></span>
<span class="line"><span>    node_factory.py   ← ⏳ 空文件，待实现</span></span>
<span class="line"><span>    loop.py           ← 🔄 旧调度器（运行中）</span></span>
<span class="line"><span>  agents/</span></span>
<span class="line"><span>    plan_agent.py     ← 🔄 旧 Agent（待重写为 Node）</span></span>
<span class="line"><span>    expand_agent.py   ← 🔄 旧 Agent（待重写为 Node）</span></span>
<span class="line"><span>    execute_agent.py  ← 🔄 旧 Agent（待重写为 Node）</span></span>
<span class="line"><span>  nodes/</span></span>
<span class="line"><span>    agents/           ← ⏳ 空目录，待填充</span></span>
<span class="line"><span>    routers/          ← ⏳ 空目录，待填充</span></span></code></pre></div><h2 id="下一步阅读" tabindex="-1">下一步阅读 <a class="header-anchor" href="#下一步阅读" aria-label="Permalink to &quot;下一步阅读&quot;">​</a></h2><ul><li>想理解 Node 基类细节：读 <a href="./node-system.html">节点系统</a></li><li>想理解认知全貌：读 <a href="./brain-architecture.html">认知架构</a></li><li>想看目标态认知拓扑：设计白皮书 <code>CortexForge 0.7</code></li></ul>`,21)])])}const g=e(p,[["render",d]]);export{u as __pageData,g as default};
